function LiveTicker({ symbol, onUpdate }: Props) {
  const onUpdateRef = useRef(onUpdate);
  useEffect(() => { onUpdateRef.current = onUpdate; }, [onUpdate]);

  useEffect(() => {
    let ws: WebSocket;
    let reconnectTimer: ReturnType<typeof setTimeout> | null = null;
    let attempt = 0;

    function connect() {
      ws = new WebSocket(`wss://api.example.com/ticker/${symbol}`);
      ws.onmessage = (e) => {
        try {
          const data = JSON.parse(e.data);
          onUpdateRef.current(data.price);
        } catch (error) {
          telemetry.error('ws_parse_error', { error });
        }
      };
      ws.onopen = () => { attempt = 0; };
      ws.onclose = () => {
        const delay = Math.min(30000, 1000 * 2 ** attempt);
        reconnectTimer = setTimeout(connect, delay);
        attempt++;
      };
    }
    connect();
    return () => {
      if (reconnectTimer) clearTimeout(reconnectTimer);
      ws.close();
    };
  }, [symbol]);

  return null;
}

