function useConfirmAction<T>(action: () => Promise<T>) {
  const [open, setOpen] = useState(false);
  const [pending, setPending] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const confirm = async () => {
    setPending(true);
    setError(null);
    try {
      const result = await action();
      setOpen(false);
      return result;
    } catch (e) {
      setError(e instanceof Error ? e.message : 'Action failed');
    } finally {
      setPending(false);
    }
  };

  return { open, pending, error, openConfirm: () => setOpen(true), close: () => setOpen(false), confirm };
}

