function OAuthCallback() {
  const [params] = useSearchParams();
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const code = params.get('code');
    const state = params.get('state');
    const redirectParam = params.get('redirect') ?? '/';

    // Only allow relative redirects (starts with / but not //)
    const safeRedirect = redirectParam.startsWith('/') && !redirectParam.startsWith('//') ? redirectParam : '/';

    if (!code) { setError('Missing code'); return; }
    if (!state || state !== sessionStorage.getItem('oauth_state')) {
      setError('Invalid state - possible CSRF');
      return;
    }

    fetch('/api/auth/exchange', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ code, state }),
      credentials: 'include'  // server sets httpOnly cookie
    })
      .then(r => { if (!r.ok) throw new Error('Exchange failed'); })
      .then(() => {
        sessionStorage.removeItem('oauth_state');
        window.location.href = safeRedirect;
      })
      .catch((e) => setError(e.message));
  }, [params]);

  if (error) return <ErrorPage error={error} />;
  return <div>Logging you in...</div>;
}
